import{apiUrl,CONFIG}from"../utils/config.js";import{getSession}from"../utils/storage.js";export async function startMobileMoneyCheckout({phoneNumber:e,plan:o,currencyCode:t}){if(!e)throw new Error("Enter the mobile money phone number.");const n=await fetch(apiUrl(CONFIG.endpoints.mobileMoney),{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${getSession()?.token||"guest"}`},body:JSON.stringify({phoneNumber:e,plan:o,currencyCode:t})});if(!n.ok)throw new Error(await n.text());return n.json()}